// ─────────────────────────────────────────────────────────────────────────────
//  Tests: ML-DSA-65 deterministic KAT
// ─────────────────────────────────────────────────────────────────────────────

/// ACVP sigGen: ML-DSA-65, sk_seed=[0u8;32], message=KAT_MSG.
/// Verifies that the implementation produces the exact expected signature bytes.
#[test]
fn acvp_mldsa65_zero_seed_siggen() {
    let sk = SigningKey65::from_bytes(&[0u8; 32]).expect("SigningKey65::from_bytes failed");
    let sig = sk.sign(KAT_MSG).expect("sign failed");
    let sig_bytes = sig.to_bytes();

    assert_eq!(
        sig_bytes.len(),
        3309,
        "ML-DSA-65 signature must be 3309 bytes (FIPS 204 Table 1)"
    );
    assert_eq!(
        sig_bytes.as_slice(),
        MLDSA65_ZERO_SEED_SIG.as_slice(),
        "ML-DSA-65 zero-seed sigGen vector mismatch — upstream library output changed"
    );
}

/// ACVP sigVer: ML-DSA-65 zero-seed KAT signature must pass verification.
///
/// Verifies the signature from `acvp_mldsa65_zero_seed_siggen` against the
/// verifying key derived from the same signing key.
#[test]
fn acvp_mldsa65_zero_seed_sigver() {
    // Derive the verifying key directly from the signing key, not from a
    // separate generate() call which consumes randomness differently.
    let sk = SigningKey65::from_bytes(&[0u8; 32]).expect("SigningKey65::from_bytes failed");
    let vk = sk.verifying_key();

    let sig = Signature65::from_bytes(&MLDSA65_ZERO_SEED_SIG).expect("Signature65::from_bytes");
    let sig_live = sk.sign(KAT_MSG).expect("sign failed");

    // The sig-from-seed must match our hardcoded vector.
    assert_eq!(
        sig_live.to_bytes().as_slice(),
        MLDSA65_ZERO_SEED_SIG.as_slice(),
        "live sig must match hardcoded vector"
    );

    // Verification must succeed.
    vk.verify(KAT_MSG, &sig).expect("sigVer must succeed");
}

/// ACVP stability: ML-DSA-65 deterministic signing is reproducible.
/// Same key + same message always produces the same signature bytes.
#[test]
fn acvp_mldsa65_determinism_is_stable() {
    let sk = SigningKey65::from_bytes(&[0u8; 32]).expect("from_bytes");
    let sig1 = sk.sign(KAT_MSG).expect("sign 1");
    let sig2 = sk.sign(KAT_MSG).expect("sign 2");
    assert_eq!(
        sig1.to_bytes(),
        sig2.to_bytes(),
        "ML-DSA-65 deterministic sign must be reproducible"
    );
}

/// ACVP sigVer: ML-DSA-65 with wrong message must fail.
#[test]
fn acvp_mldsa65_sigver_wrong_message_fails() {
    // Use the correct matching verifying key, then verify wrong message fails.
    let sk = SigningKey65::from_bytes(&[0u8; 32]).expect("from_bytes");
    let vk = sk.verifying_key();

    let sig = Signature65::from_bytes(&MLDSA65_ZERO_SEED_SIG).expect("from_bytes");
    let wrong_msg = b"This is NOT the KAT message";
    assert!(
        vk.verify(wrong_msg, &sig).is_err(),
        "sigVer must fail on wrong message"
    );
}

