//  Tests: ML-DSA-44 deterministic KAT (sigGen / sigVer)
// ─────────────────────────────────────────────────────────────────────────────

/// ACVP sigGen: ML-DSA-44, sk_seed=[0u8;32], msg=KAT_MSG.
/// Verifies exact signature length and byte stability.
#[test]
fn acvp_mldsa44_zero_seed_siggen_length() {
    let sk = SigningKey44::from_bytes(&[0u8; 32]).expect("SigningKey44::from_bytes");
    let sig = sk.sign(KAT_MSG).expect("sign");
    let sig_bytes = sig.to_bytes();
    assert_eq!(
        sig_bytes.len(),
        2420,
        "ML-DSA-44 signature must be 2420 bytes (FIPS 204 Table 1)"
    );
}

/// ACVP sigGen stability: ML-DSA-44 sign is deterministic.
#[test]
fn acvp_mldsa44_determinism_is_stable() {
    let sk = SigningKey44::from_bytes(&[0u8; 32]).expect("from_bytes");
    let sig1 = sk.sign(KAT_MSG).expect("sign 1");
    let sig2 = sk.sign(KAT_MSG).expect("sign 2");
    assert_eq!(
        sig1.to_bytes(),
        sig2.to_bytes(),
        "ML-DSA-44 deterministic sign must be reproducible"
    );
}

/// ACVP sigVer: ML-DSA-44 signature verifies against the matching verifying key.
///
/// The verifying key is derived directly from the signing key (not from a
/// separate `generate` call with the same seed, which produces a different key
/// because `generate_from_rng` consumes randomness differently).
#[test]
fn acvp_mldsa44_zero_seed_sigver() {
    let sk = SigningKey44::from_bytes(&[0u8; 32]).expect("from_bytes");
    let vk = sk.verifying_key();
    let sig = sk.sign(KAT_MSG).expect("sign");
    vk.verify(KAT_MSG, &sig).expect("sigVer must succeed");
}

/// ACVP sigVer negative: ML-DSA-44 fails with wrong message.
/// ACVP sigVer negative: ML-DSA-44 fails with wrong message.
#[test]
fn acvp_mldsa44_sigver_wrong_message_fails() {
    // Use the correct vk derived from the sk; verify that wrong message fails.
    let sk = SigningKey44::from_bytes(&[0u8; 32]).expect("from_bytes");
    let vk = sk.verifying_key();
    let sig = sk.sign(KAT_MSG).expect("sign");
    assert!(
        vk.verify(b"wrong message", &sig).is_err(),
        "sigVer must fail on wrong message"
    );
}

/// ACVP sigVer negative: ML-DSA-44 fails with wrong verifying key.
#[test]
fn acvp_mldsa44_sigver_wrong_key_fails() {
    use oxicrypto_pq::mldsa::MlDsa44;
    use rand_chacha::ChaCha20Rng;
    use rand_core::SeedableRng;

    let sk = SigningKey44::from_bytes(&[0u8; 32]).expect("from_bytes");
    let sig = sk.sign(KAT_MSG).expect("sign");

    // Different seed → different key pair; its verifying key must not accept our sig.
    let mut rng2 = ChaCha20Rng::from_seed([0xFFu8; 32]);
    let (_, vk2) = MlDsa44::generate(&mut rng2);
    assert!(
        vk2.verify(KAT_MSG, &sig).is_err(),
        "sigVer must fail on wrong verifying key"
    );
}

// ─────────────────────────────────────────────────────────────────────────────
//  Tests: ML-DSA-87 KAT (via 2 MiB thread — see OXICRYPTO_MLDSA_STACK)
// ─────────────────────────────────────────────────────────────────────────────

/// ACVP sigGen: ML-DSA-87 signature has correct length and is deterministic.
#[test]
fn acvp_mldsa87_siggen_length_and_determinism() {
    std::thread::Builder::new()
        .stack_size(oxicrypto_pq::OXICRYPTO_MLDSA_STACK)
        .spawn(|| {
            use oxicrypto_pq::mldsa::SigningKey87;
            let sk = SigningKey87::from_bytes(&[0u8; 32]).expect("from_bytes87");
            let sig1 = sk.sign(KAT_MSG).expect("sign87 1");
            let sig2 = sk.sign(KAT_MSG).expect("sign87 2");
            let sig1_bytes = sig1.to_bytes();
            assert_eq!(
                sig1_bytes.len(),
                4627,
                "ML-DSA-87 signature must be 4627 bytes (FIPS 204 Table 1)"
            );
            assert_eq!(
                sig1_bytes,
                sig2.to_bytes(),
                "ML-DSA-87 sign must be deterministic"
            );
        })
        .expect("thread spawn failed")
        .join()
        .expect("thread panicked");
}

/// ACVP sigVer: ML-DSA-87 sign-then-verify round-trip succeeds.
#[test]
fn acvp_mldsa87_sigver_round_trip() {
    std::thread::Builder::new()
        .stack_size(oxicrypto_pq::OXICRYPTO_MLDSA_STACK)
        .spawn(|| {
            use oxicrypto_pq::mldsa::MlDsa87;
            use rand_chacha::ChaCha20Rng;
            use rand_core::SeedableRng;

            let mut rng = ChaCha20Rng::from_seed([0u8; 32]);
            let (sk, vk) = MlDsa87::generate(&mut rng);
            let sig = sk.sign(KAT_MSG).expect("sign87");
            vk.verify(KAT_MSG, &sig).expect("sigVer87 must succeed");
        })
        .expect("thread spawn failed")
        .join()
        .expect("thread panicked");
}

/// ACVP sigVer negative: ML-DSA-87 fails with wrong message.
#[test]
fn acvp_mldsa87_sigver_wrong_message_fails() {
    std::thread::Builder::new()
        .stack_size(oxicrypto_pq::OXICRYPTO_MLDSA_STACK)
        .spawn(|| {
            use oxicrypto_pq::mldsa::MlDsa87;
            use rand_chacha::ChaCha20Rng;
            use rand_core::SeedableRng;

            let mut rng = ChaCha20Rng::from_seed([0u8; 32]);
            let (sk, vk) = MlDsa87::generate(&mut rng);
            let sig = sk.sign(KAT_MSG).expect("sign87");
            assert!(
                vk.verify(b"wrong message", &sig).is_err(),
                "sigVer must fail on wrong message"
            );
        })
        .expect("thread spawn failed")
        .join()
        .expect("thread panicked");
}
